record.field:
# Agrupar registros seleccionados por (moneda, partner)
groups = {}
for rec in records:
    key = (
        rec.x_studio_currency_id.id or env.company.currency_id.id,
        rec.x_studio_compaia.id if rec.x_studio_compaia else env.company.partner_id.id,
    )
    groups.setdefault(key, records.browse())
    groups[key] |= rec

created_ids = []
for (currency_id, partner_id), recs in groups.items():
    # Fecha de entrega: la más temprana del grupo
    primer_entrega = min(recs, key=lambda r: r.x_studio_date_stop or r.create_date)

    # Armar líneas con (0, 0, vals) para crear PO + líneas en un solo create
    # Por qué: crear líneas por separado dispara trigger account.move.purchase_id
    # que falla porque ese campo no es stored en Odoo 19
    order_lines = []
    line_rec_map = []
    for rec in recs:
        product = env['product.template'].browse(rec.x_studio_producto.id)
        line_vals = {
            'product_id': product.product_variant_id.id,
            'product_qty': rec.x_studio_cantidad,
            'price_unit': product.standard_price,
            'name': rec.x_name,
        }
        order_lines.append((0, 0, line_vals))
        line_rec_map.append(rec)

    # Por qué: order_line DEBE ir en el create, no en write separado.
    # write() dispara modified() → busca account.move.purchase_id (no stored en Odoo 19)
    po = env['purchase.order'].create({
        'partner_id': partner_id,
        'currency_id': currency_id,
        'date_order': primer_entrega.x_studio_date_stop,
        'order_line': order_lines,
    })

    # Vincular cada registro con su línea de PO
    for idx, po_line in enumerate(po.order_line):
        if idx < len(line_rec_map):
            line_rec_map[idx].write({
                'x_studio_ppto_comp': po.id,
                'x_studio_linea_ppto_cpras': po_line.id,
                'x_studio_stage_id': 2,
            })
    created_ids.append(po.id)

# Retornar acción para ver las POs creadas
if len(created_ids) == 1:
    action = {
        'type': 'ir.actions.act_window',
        'res_model': 'purchase.order',
        'res_id': created_ids[0],
        'view_mode': 'form',
        'target': 'current',
    }
else:
    action = {
        'type': 'ir.actions.act_window',
        'res_model': 'purchase.order',
        'domain': [('id', 'in', created_ids)],
        'view_mode': 'list,form',
        'target': 'current',
    }
